#include<bits/stdc++.h>
using namespace std;
int main(void){
	int n,m,p[100350],sum=0,mim=0;
	cin>>n>>m;
	for(int i=1;i<=m;++i)cin>>p[i];
	sort(p+1,p+m+1,greater<int>());
	for(int i=1;i<=min(n,m);++i){
		if(sum<=p[i]*i){
			sum=p[i]*i;
			mim=p[i];
		}
	}
	cout<<mim<<" "<<sum;
	return 0;
}
